import React from "react";

const ImageSection = () => {
  return (
    <section style={{ maxWidth: "900px", margin: "0 auto 4rem", textAlign: "center" }}>
      <img
        src="/media/aboutus/drinks_hands.jpg"
        alt="Hydration drinks"
        style={{ maxWidth: "100%", borderRadius: "1rem" }}
      />
    </section>
  );
};

export default ImageSection;
